            ['question_fr' => 'Puis-je annuler ou déplacer mon rendez-vous ?', 'question_en' => 'Can I cancel or reschedule my appointment?', 'answer_fr' => 'Oui. Merci de prévenir le plus tôt possible, idéalement au moins 24h à l’avance, afin de libérer le créneau.', 'answer_en' => 'Yes. Please notify us as early as possible, ideally at least 24 hours in advance, so the slot can be released.', 'category' => 'booking', 'sort_order' => 10],
            ['question_fr' => 'Les informations du site remplacent-elles une consultation ?', 'question_en' => 'Does the website information replace a consultation?', 'answer_fr' => 'Non. Les informations du site sont fournies à titre informatif et ne remplacent pas une consultation personnalisée ou un avis médical.', 'answer_en' => 'No. Website information is provided for informational purposes and does not replace a personalized consultation or medical advice.', 'category' => 'medical', 'sort_order' => 11],
            ['question_fr' => 'Comment fonctionne IA Recommendation ?', 'question_en' => 'How does AI Recommendation work?', 'answer_fr' => 'L’outil d’orientation IA peut aider à préparer votre demande en suggérant des pistes à discuter avec Asthetika. Il ne remplace pas l’avis d’un professionnel.', 'answer_en' => 'The AI guidance tool can help prepare your request by suggesting topics to discuss with Asthetika. It does not replace professional advice.', 'category' => 'ai', 'sort_order' => 12],
        ] as $faq) {
