        foreach ([
            ['title_fr' => 'Politique d’annulation', 'title_en' => 'Cancellation policy', 'slug' => 'cancellation-policy', 'content_fr' => "Merci de prévenir au moins 24h à l’avance en cas d’annulation ou de report. Cela nous permet de réorganiser les rendez-vous et de proposer le créneau à une autre personne.\n\nEn cas d’empêchement de dernière minute, contactez Asthetika par téléphone ou WhatsApp au +216 26 500 507.", 'content_en' => "Please notify us at least 24 hours in advance for cancellations or rescheduling. This helps us reorganize appointments and offer the slot to another client.\n\nIn case of a last-minute issue, contact Asthetika by phone or WhatsApp at +216 26 500 507.", 'sort_order' => 1],
            ['title_fr' => 'Politique de confidentialité', 'title_en' => 'Privacy policy', 'slug' => 'privacy-policy', 'content_fr' => "Les informations transmises via le site ou lors de la prise de rendez-vous sont utilisées uniquement pour gérer votre demande, votre rendez-vous et le suivi de votre prise en charge.\n\nAsthetika ne vend pas vos données personnelles. Vous pouvez demander la modification ou la suppression de vos informations en nous contactant.", 'content_en' => "Information submitted through the website or during booking is used only to manage your request, appointment, and follow-up.\n\nAsthetika does not sell personal data. You may request modification or deletion of your information by contacting us.", 'sort_order' => 2],
            ['title_fr' => 'Conditions générales', 'title_en' => 'Terms of service', 'slug' => 'terms-of-service', 'content_fr' => "Les informations du site sont fournies à titre informatif et ne remplacent pas une consultation personnalisée. Les soins, conseils et recommandations sont adaptés selon chaque situation.\n\nL’utilisation du site implique l’acceptation de ces conditions.", 'content_en' => "The information on this website is provided for informational purposes and does not replace a personalized consultation. Treatments, advice, and recommendations are adapted to each case.\n\nUsing the website implies acceptance of these terms.", 'sort_order' => 3],
            ['title_fr' => 'Politique de réservation', 'title_en' => 'Booking policy', 'slug' => 'booking-policy', 'content_fr' => "La réservation en ligne permet de choisir un soin, une date et un créneau disponibles. Asthetika peut vous contacter si une précision est nécessaire avant le rendez-vous.\n\nMerci de vérifier vos coordonnées avant confirmation.", 'content_en' => "Online booking allows you to choose a treatment, date, and available time slot. Asthetika may contact you if clarification is needed before the appointment.\n\nPlease check your contact details before confirmation.", 'sort_order' => 4],
            ['title_fr' => 'Consentement image', 'title_en' => 'Image consent policy', 'slug' => 'image-consent-policy', 'content_fr' => "Aucune photo identifiable ne doit être utilisée publiquement sans accord explicite. Les images publiées doivent respecter la confidentialité et l’accord de la personne concernée.\n\nVous pouvez demander le retrait d’une image vous concernant en contactant Asthetika.", 'content_en' => "No identifiable photo should be used publicly without explicit consent. Published images must respect privacy and the agreement of the person concerned.\n\nYou may request removal of an image concerning you by contacting Asthetika.", 'sort_order' => 5],
            ['title_fr' => 'Information médicale', 'title_en' => 'Medical disclaimer', 'slug' => 'medical-disclaimer', 'content_fr' => "Les contenus du site, y compris les informations liées aux soins et à l’orientation IA, ne remplacent pas une consultation médicale personnalisée. Toute recommandation doit être adaptée à votre situation.\n\nEn cas de doute, demandez un avis professionnel.", 'content_en' => "Website content, including treatment information and AI guidance, does not replace a personalized medical consultation. Any recommendation must be adapted to your situation.\n\nIf in doubt, seek professional advice.", 'sort_order' => 6],
        ] as $policy) {
